)

var DB *gorm.DB

func LoadEnv() {
	// Priority order:
	// 1) ENV_FILE explicit path
	// 2) project root .env.backend
	// 3) fallback to system environment variables
	envFile := os.Getenv("ENV_FILE")
	if envFile != "" {
		if err := godotenv.Load(envFile); err != nil {
			log.Printf("Failed to load env file from ENV_FILE (%s): %v", envFile, err)
		}
		return
	}

	candidates := []string{
		filepath.Join("..", "..", ".env.backend"),
		".env.backend",
	}

	for _, path := range candidates {
		if _, err := os.Stat(path); err == nil {
			if err := godotenv.Load(path); err != nil {
				log.Printf("Failed to load env file (%s): %v", path, err)
			}
			return
		}
	}

	log.Println("No .env.backend file found, using system environment variables")
}

func ConnectDB() {
	host := os.Getenv("DB_HOST")
	port := os.Getenv("DB_PORT")
	user := os.Getenv("DB_USER")
	password := os.Getenv("DB_PASSWORD")
	dbname := os.Getenv("DB_NAME")

	dsn := fmt.Sprintf("host=%s user=%s password=%s dbname=%s port=%s sslmode=disable TimeZone=Asia/Ho_Chi_Minh",
		host, user, password, dbname, port)

	db, err := gorm.Open(postgres.Open(dsn), &gorm.Config{})
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}

	fmt.Println("Connected to PostgreSQL successfully!")
	DB = db

	// Auto Migration: GORM will automatically create/update the table schema
	err = db.AutoMigrate(&domain.User{}, &domain.Session{}, &domain.EmailVerificationToken{})
	if err != nil {
		log.Fatalf("Failed to auto migrate: %v", err)
	}
	fmt.Println("Auto migration completed!")
}

package repository

import (
	"time"

	"auth-user-management-service/internal/domain"

	"gorm.io/gorm"
)

// EmailVerificationRepository defines persistence operations for email verification tokens.
type EmailVerificationRepository interface {
	CreateToken(token *domain.EmailVerificationToken) error
	FindByTokenHash(tokenHash string) (*domain.EmailVerificationToken, error)
	MarkUsed(id uint) error
	DeleteActiveTokensByUserID(userID uint) error
	PurgeExpired(now time.Time) error
}

type emailVerificationRepositoryImpl struct {
	db *gorm.DB
}

// NewEmailVerificationRepository creates a new verification repository instance.
func NewEmailVerificationRepository(db *gorm.DB) EmailVerificationRepository {
	return &emailVerificationRepositoryImpl{db: db}
}

func (r *emailVerificationRepositoryImpl) CreateToken(token *domain.EmailVerificationToken) error {
	return r.db.Create(token).Error
}

func (r *emailVerificationRepositoryImpl) FindByTokenHash(tokenHash string) (*domain.EmailVerificationToken, error) {
	var token domain.EmailVerificationToken
	err := r.db.Where("token_hash = ?", tokenHash).First(&token).Error
	if err != nil {
		return nil, err
	}
	return &token, nil
}

func (r *emailVerificationRepositoryImpl) MarkUsed(id uint) error {
	now := time.Now()
	return r.db.Model(&domain.EmailVerificationToken{}).
		Where("id = ? AND used_at IS NULL", id).
		Update("used_at", now).Error
}

func (r *emailVerificationRepositoryImpl) DeleteActiveTokensByUserID(userID uint) error {
	return r.db.Where("user_id = ? AND used_at IS NULL", userID).
		Delete(&domain.EmailVerificationToken{}).Error
}

func (r *emailVerificationRepositoryImpl) PurgeExpired(now time.Time) error {
	return r.db.Where("expires_at < ?", now).
		Delete(&domain.EmailVerificationToken{}).Error
}

package domain

import (
	"time"

	"gorm.io/gorm"
)

// User represents the user record in the database (Entity/Model)
type User struct {
	ID        uint           `gorm:"primaryKey;autoIncrement" json:"userId"`
	Username  string         `gorm:"type:varchar(100);not null" json:"username"`
	Email     string         `gorm:"type:varchar(100);uniqueIndex;not null" json:"email"`
	Password  string         `gorm:"type:varchar(255);not null" json:"-"` // Hide password when parse/marshal JSON
	Role      string         `gorm:"type:varchar(50);not null;default:'member'" json:"role"` // manager or member
	CreatedAt time.Time      `json:"createdAt"`
	UpdatedAt time.Time      `json:"updatedAt"`
	DeletedAt gorm.DeletedAt `gorm:"index" json:"-"`
}

