  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  useEffect(() => {
    let mounted = true;

    async function verify() {
      if (!token) {
        if (mounted) {
          setError("Missing verification token");
          setLoading(false);
        }
        return;
      }

      try {
        const response = await verifyEmailApi(token);
